import type { RangeItem } from '../types/range-legend.js';

export const getMarkers = (items: RangeItem[], isReversed: boolean) => {
  const markers = items
    .reduce((acc, cur, itemIdx, self) => {
      const { from, to } = cur;

      const isFromHidden = isReversed
        ? self.some(
            (item, idx) => idx > itemIdx && item.from > from && from > item.to,
          )
        : self.some(
            (item, idx) => idx > itemIdx && item.from < from && from < item.to,
          );

      const isToHidden = isReversed
        ? self.some(
            (item, idx) => idx > itemIdx && item.from > to && to > item.to,
          )
        : self.some(
            (item, idx) => idx > itemIdx && item.from < to && to < item.to,
          );

      if (!isFromHidden) {
        acc.push(from);
      }

      if (!isToHidden) {
        acc.push(to);
      }

      return acc;
    }, [] as number[])
    .sort((a, b) => a - b);
  const uniqueMarkers = new Set(markers);

  const singlePointRangeMarkers = items.reduce((acc, cur) => {
    if (cur.from === cur.to) {
      acc.add(cur.from);
    }

    return acc;
  }, new Set<number>([]));

  return { itemMarkers: uniqueMarkers, singlePointRangeMarkers };
};
